"use strict";(globalThis.webpackChunkship_it_book=globalThis.webpackChunkship_it_book||[]).push([[212],{17(e,t,o){o.r(t),o.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>u,frontMatter:()=>r,metadata:()=>n,toc:()=>h});const n=JSON.parse('{"id":"part-2-find-the-problem/chapter-2-2-reading-markets","title":"Chapter 2.2 \u2014 Reading Markets Without an MBA","description":"Real market research for developers.","source":"@site/docs/part-2-find-the-problem/chapter-2-2-reading-markets.mdx","sourceDirName":"part-2-find-the-problem","slug":"/part-2-find-the-problem/chapter-2-2-reading-markets","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-2-reading-markets","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Chapter 2.2 \u2014 Reading Markets Without an MBA","description":"Real market research for developers.","sidebar_label":"2.2 \u2014 Reading Markets Without an MBA"},"sidebar":"book","previous":{"title":"2.1 \u2014 Finding Your Identity","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-1-finding-your-identity"},"next":{"title":"2.3 \u2014 Problem-First vs Solution-First","permalink":"/ship-it-book/part-2-find-the-problem/chapter-2-3-problem-first-thinking"}}');var s=o(4848),i=o(8453);const r={title:"Chapter 2.2 \u2014 Reading Markets Without an MBA",description:"Real market research for developers.",sidebar_label:"2.2 \u2014 Reading Markets Without an MBA"},a="Reading Markets Without an MBA",l={},h=[{value:"The Developer&#39;s Advantage",id:"the-developers-advantage",level:2},{value:"The Mom Test Framework",id:"the-mom-test-framework",level:2},{value:"How to Use Reddit, Twitter, and GitHub for Market Research",id:"how-to-use-reddit-twitter-and-github-for-market-research",level:2},{value:"Real Examples of Products Found Through Market Research",id:"real-examples-of-products-found-through-market-research",level:2},{value:"The 5-Step Market Scan",id:"the-5-step-market-scan",level:2},{value:"Step 1: Find where people complain",id:"step-1-find-where-people-complain",level:3},{value:"Step 2: Look for patterns",id:"step-2-look-for-patterns",level:3},{value:"Step 3: Assess the pain level",id:"step-3-assess-the-pain-level",level:3},{value:"Step 4: Analyze competitors properly",id:"step-4-analyze-competitors-properly",level:3},{value:"Step 5: Talk to potential users",id:"step-5-talk-to-potential-users",level:3},{value:"The Difference Between Problem Validation and Solution Validation",id:"the-difference-between-problem-validation-and-solution-validation",level:2},{value:"The Painted Door Test",id:"the-painted-door-test",level:2},{value:"The Hard Truth",id:"the-hard-truth",level:2},{value:"Your Turn",id:"your-turn",level:2},{value:"What You Learned",id:"what-you-learned",level:2}];function d(e){const t={h1:"h1",h2:"h2",h3:"h3",header:"header",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"reading-markets-without-an-mba",children:"Reading Markets Without an MBA"})}),"\n",(0,s.jsx)(t.p,{children:"You don't need a business degree to understand markets. You need curiosity, a systematic approach, and the willingness to talk to strangers."}),"\n",(0,s.jsx)(t.p,{children:"Market research sounds intimidating. It sounds like something people in suits do with spreadsheets and consultants. But at its core, market research is just answering one question: do people have a problem they'll pay to solve?"}),"\n",(0,s.jsx)(t.h2,{id:"the-developers-advantage",children:"The Developer's Advantage"}),"\n",(0,s.jsx)(t.p,{children:"You can build. This gives you a superpower that MBA graduates don't have. You can validate an idea by building a prototype in a weekend. They need to hire an agency."}),"\n",(0,s.jsx)(t.p,{children:"Use your ability to build as your research tool. Don't just ask people if they'd use your product. Build a rough version and put it in front of them. Their behavior will tell you more than their words ever will."}),"\n",(0,s.jsx)(t.p,{children:"But here's the trap: building too early is as dangerous as building too late. If you build before you understand the problem, you're guessing. Guessing leads to wasted months. The advantage of being able to build fast is wasted if you build the wrong thing fast."}),"\n",(0,s.jsx)(t.p,{children:"Use your building power strategically. Build to learn, not to launch."}),"\n",(0,s.jsx)(t.h2,{id:"the-mom-test-framework",children:"The Mom Test Framework"}),"\n",(0,s.jsx)(t.p,{children:"Rob Fitzpatrick wrote a book called The Mom Test. The central insight is simple: people will lie to you to be nice. Your mom will tell you your idea is great because she loves you. But a stranger who takes out their wallet? That's real feedback."}),"\n",(0,s.jsx)(t.p,{children:"The Mom Test gives you rules for asking questions that get honest answers."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Rule 1: Talk about their life, not your idea."})}),"\n",(0,s.jsx)(t.p,{children:"Don't say: \"Would you use a tool that auto-generates invoices?\" This is a leading question. People will say yes because it's easier than saying no."}),"\n",(0,s.jsx)(t.p,{children:'Instead: "How do you handle invoicing right now? Walk me through your last month." Now you\'re learning about their actual behavior, not their hypothetical reactions.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Rule 2: Look for facts, not compliments."})}),"\n",(0,s.jsx)(t.p,{children:'When you mention your idea and someone says "that\'s interesting" or "that sounds useful," these are compliments. They cost nothing. They mean nothing.'}),"\n",(0,s.jsx)(t.p,{children:'Instead, ask for specifics. "What happened the last time you tried to solve this?" Specific stories are real. General enthusiasm is noise.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"Rule 3: Watch for commitment signals."})}),"\n",(0,s.jsx)(t.p,{children:"Real interest looks like: pulling out their calendar, asking about pricing, introducing you to a colleague, offering to test a prototype. Anything else is politeness."}),"\n",(0,s.jsx)(t.p,{children:'One sign of low commitment: asking when it will be ready. This sounds positive but costs nothing. Compare that to "can I pay for a year upfront if you add this feature?" That\'s a real signal.'}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:'Rule 4: Avoid "would you" questions.'})}),"\n",(0,s.jsx)(t.p,{children:'"Would you pay for X?" People will say yes to be agreeable. They\'re not imagining the friction of actually paying.'}),"\n",(0,s.jsx)(t.p,{children:"Instead: \"What have you spent money on to solve this problem?\" Past behavior predicts future behavior. If they haven't spent anything, they probably won't start with you."}),"\n",(0,s.jsx)(t.p,{children:"The Mom Test isn't about being cynical. It's about not fooling yourself. The people who give you the most useful feedback are often the ones who seem most critical. They're the ones who care enough to tell you the truth."}),"\n",(0,s.jsx)(t.h2,{id:"how-to-use-reddit-twitter-and-github-for-market-research",children:"How to Use Reddit, Twitter, and GitHub for Market Research"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Reddit"})," is the best free market research tool in existence. Every subreddit is a focus group of people who self-identify around a specific interest or problem."]}),"\n",(0,s.jsx)(t.p,{children:"Go to subreddits related to your target audience. Sort by top posts this month, this year, all time. The most upvoted posts in any niche community tell you what that community cares about most."}),"\n",(0,s.jsx)(t.p,{children:'Then sort by new and scroll. The complaints, the questions, the "does anyone else..." posts are your raw data. Collect them.'}),"\n",(0,s.jsx)(t.p,{children:"Search for specific phrases:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:'"Is there a way to..."'}),"\n",(0,s.jsx)(t.li,{children:'"I wish..."'}),"\n",(0,s.jsx)(t.li,{children:'"Why is it so hard to..."'}),"\n",(0,s.jsx)(t.li,{children:'"Does anyone know how to..."'}),"\n",(0,s.jsx)(t.li,{children:'"Am I the only one who..."'}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Copy the exact text of complaints into a document. Include upvote counts. High upvotes means many people share that pain."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Twitter"}),' is where people vent in real time. Search for your problem space using keywords. Look for tweets that end with "..." \u2014 that trailing ellipsis is often a sign of frustration.']}),"\n",(0,s.jsx)(t.p,{children:'Search for "I wish there was a tool that" or "why can\'t I just" or "it\'s 202[year] and we still can\'t". These are goldmines.'}),"\n",(0,s.jsx)(t.p,{children:"Look for threads where someone rants about a problem and the replies are full of people agreeing. That's a validated market. Build what the original poster described."}),"\n",(0,s.jsx)(t.p,{children:"Follow the accounts that complain the most about your problem space. They're your ideal users. They care enough to rant. They'll care enough to pay."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"GitHub"})," is unique because it shows you what developers are actually building and using."]}),"\n",(0,s.jsx)(t.p,{children:"Look at issues in popular projects. Feature requests that have hundreds of upvotes are market demand. The most requested features in open-source tools often point to gaps that a commercial product could fill."}),"\n",(0,s.jsx)(t.p,{children:"Search for topics related to your problem area. Look at the most starred repositories. Read their READMEs. The projects with the most stars are solving real problems \u2014 but they might be solving them poorly. Your opportunity is the gap between what exists and what users need."}),"\n",(0,s.jsx)(t.p,{children:"Look at alternativeTo.net and product hunt too. See what people switch from and what they complain about in comments."}),"\n",(0,s.jsx)(t.h2,{id:"real-examples-of-products-found-through-market-research",children:"Real Examples of Products Found Through Market Research"}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Nomad List"})," started as a simple Google Sheet. Pieter Levels was frustrated that there was no good data about which cities were best for digital nomads. He searched online and found conversations on Reddit and Facebook groups where people were asking the exact same questions. He aggregated the data manually, published it, and thousands of people showed up. The spreadsheet became a website. The website became a community. The community became a business."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Remote OK"}),' (also by Pieter Levels) started the same way. He noticed on Reddit that people kept asking "where do I find remote jobs?" and the existing job boards had terrible UX. He searched for complaints about remote job boards, found hundreds, and built a simpler alternative. It now generates millions in revenue.']}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Tally.so"})," started when founder Filip noticed a Reddit thread complaining about Typeform's pricing. Typeform was the gold standard for forms but cost hundreds of dollars per month. He searched for similar complaints, found thousands of people wishing for a simpler, cheaper alternative. He built Tally as a no-code form builder with a free tier. It now has hundreds of thousands of users."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Unsplash"})," started as a Tumblr blog. Founder Mikael Cho noticed that designers on Dribbble and Reddit were constantly looking for free high-quality photos. The existing stock photo sites were expensive and corporate. He created a simple blog posting free photos. The demand was immediate. It became the largest free photo library in the world."]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Morning Brew"})," started as a simple email newsletter. Founder Alex Lieberman noticed that his business school classmates were checking financial news but found traditional sources too dense. He started a daily email that summarized business news in a conversational tone. The first subscribers came from Reddit and Twitter. It grew to 4 million subscribers and sold for $75 million."]}),"\n",(0,s.jsx)(t.p,{children:"Common pattern across all of them: the founder noticed a recurring complaint, validated it by seeing it in multiple places, and built a simple solution. No complex business plans. No million-dollar research budgets. Just paying attention to what people were saying."}),"\n",(0,s.jsx)(t.h2,{id:"the-5-step-market-scan",children:"The 5-Step Market Scan"}),"\n",(0,s.jsx)(t.h3,{id:"step-1-find-where-people-complain",children:"Step 1: Find where people complain"}),"\n",(0,s.jsx)(t.p,{children:"Go to Reddit, Hacker News, Twitter, GitHub Issues, and product review sites. Search for phrases like:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:'"I wish there was a way to..."'}),"\n",(0,s.jsx)(t.li,{children:'"It\'s so annoying that..."'}),"\n",(0,s.jsx)(t.li,{children:'"Why doesn\'t anyone build..."'}),"\n",(0,s.jsx)(t.li,{children:'"The only option is X but it\'s terrible because..."'}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"These are signal. Every complaint is a potential product. Collect them. Don't judge them yet. Just gather."}),"\n",(0,s.jsx)(t.p,{children:'Create a document called "complaints.md". Make a bullet list. Include the source, the exact quote, and the number of upvotes or replies. This document is your raw material.'}),"\n",(0,s.jsx)(t.h3,{id:"step-2-look-for-patterns",children:"Step 2: Look for patterns"}),"\n",(0,s.jsx)(t.p,{children:"After you collect 20-30 complaints, look for patterns. Are multiple people complaining about the same thing? Is the same pain point showing up in different communities?"}),"\n",(0,s.jsx)(t.p,{children:"Patterns matter more than individual complaints. One person complaining might just be a loud voice. Ten people complaining about the same problem is a market opportunity."}),"\n",(0,s.jsx)(t.p,{children:"Categorize complaints by theme. For example:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:'"Too expensive" (5 complaints)'}),"\n",(0,s.jsx)(t.li,{children:'"Too complex" (8 complaints)'}),"\n",(0,s.jsx)(t.li,{children:'"Missing feature" (12 complaints)'}),"\n",(0,s.jsx)(t.li,{children:'"Bad UX" (7 complaints)'}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"The category with the most complaints is your best opportunity. But also look for the category where existing solutions ignore the pain completely. That's your opening."}),"\n",(0,s.jsx)(t.h3,{id:"step-3-assess-the-pain-level",children:"Step 3: Assess the pain level"}),"\n",(0,s.jsx)(t.p,{children:"Not all problems are worth solving. You need problems that hurt enough for people to take action."}),"\n",(0,s.jsx)(t.p,{children:"Ask yourself: does this problem cause people to lose money, waste time, or feel frustrated regularly? If the answer is no, the problem is probably not painful enough. People tolerate minor annoyances. They pay to eliminate major pain."}),"\n",(0,s.jsx)(t.p,{children:"Here's a pain scale:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Level 1"}),': Mild annoyance. "It would be nice if this were better." Nobody pays for level 1.']}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Level 2"}),': Frustration. "This is annoying but I deal with it." Some people pay, but churn is high.']}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Level 3"}),': Pain. "This is costing me time or money every week." Most people in this category will pay.']}),"\n",(0,s.jsxs)(t.li,{children:[(0,s.jsx)(t.strong,{children:"Level 4"}),': Crisis. "This is an emergency." They\'ll pay almost anything for a solution.']}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Aim for level 3 or 4. If the problem is only level 1 or 2, move on."}),"\n",(0,s.jsx)(t.h3,{id:"step-4-analyze-competitors-properly",children:"Step 4: Analyze competitors properly"}),"\n",(0,s.jsx)(t.p,{children:"Search for existing solutions to the problem. Try them. Note what they do well and where they fall short."}),"\n",(0,s.jsx)(t.p,{children:"If there are no existing solutions, that's a red flag, not a green one. It might mean nobody cares enough to build a solution. If there are many existing solutions, that's validation that the market exists. Your job is to find the gap they're all missing."}),"\n",(0,s.jsx)(t.p,{children:(0,s.jsx)(t.strong,{children:"The competitor analysis framework:"})}),"\n",(0,s.jsxs)(t.ol,{children:["\n",(0,s.jsx)(t.li,{children:"List every competitor, including non-obvious ones (spreadsheets, manual processes, doing nothing)."}),"\n",(0,s.jsxs)(t.li,{children:["For each, write down:","\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"What do they do well?"}),"\n",(0,s.jsx)(t.li,{children:"What do they do poorly?"}),"\n",(0,s.jsx)(t.li,{children:"Who do they serve well?"}),"\n",(0,s.jsx)(t.li,{children:"Who do they ignore?"}),"\n"]}),"\n"]}),"\n",(0,s.jsx)(t.li,{children:"Read their reviews. G2, Capterra, App Store, Reddit. Reviews are gold because they tell you what users actually want."}),"\n",(0,s.jsx)(t.li,{children:"Look for the complaints that every competitor gets. If all project management tools have bad mobile apps, that's a gap. If all email tools have terrible spam filters, that's a gap."}),"\n",(0,s.jsx)(t.li,{children:'Ask yourself: is the gap big enough to build a company on? Not just "can I build a slightly better version?" but "can I build something that solves this so differently that customers will switch?"'}),"\n"]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"The copycat trap:"})," If you build a slightly better version of an existing tool, you lose. Incumbents have distribution, trust, and resources. You need to be dramatically different, not slightly better. Find the underserved segment and build for them exclusively."]}),"\n",(0,s.jsx)(t.h3,{id:"step-5-talk-to-potential-users",children:"Step 5: Talk to potential users"}),"\n",(0,s.jsx)(t.p,{children:"This is the step most developers skip. It's also the most important."}),"\n",(0,s.jsx)(t.p,{children:"Find five people who have the problem. Ask them using the Mom Test framework:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"How do you handle this problem today?"}),"\n",(0,s.jsx)(t.li,{children:"What's the most frustrating part of your current solution?"}),"\n",(0,s.jsx)(t.li,{children:"If you could wave a magic wand, what would change?"}),"\n",(0,s.jsx)(t.li,{children:"How much would you pay for a solution?"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Don't pitch your idea. Don't talk about your product. Just listen."}),"\n",(0,s.jsx)(t.p,{children:"Aim for 15-20 conversations. After 20 conversations, you should have a clear picture of the problem, the existing solutions, and the gap. If you don't, keep talking."}),"\n",(0,s.jsx)(t.h2,{id:"the-difference-between-problem-validation-and-solution-validation",children:"The Difference Between Problem Validation and Solution Validation"}),"\n",(0,s.jsx)(t.p,{children:"These are two different things. Most developers skip problem validation and jump straight to solution validation."}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Problem validation"})," answers: does this problem exist? Do people have it? Is it painful enough that they'd do something about it?"]}),"\n",(0,s.jsxs)(t.p,{children:[(0,s.jsx)(t.strong,{children:"Solution validation"})," answers: would people use my specific solution to this problem?"]}),"\n",(0,s.jsx)(t.p,{children:"Problem validation comes first. Always. You can't validate a solution to a problem that hasn't been validated yet."}),"\n",(0,s.jsx)(t.p,{children:"Here's what problem validation looks like:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"You've spoken to 10+ people who confirm they have the problem"}),"\n",(0,s.jsx)(t.li,{children:"You've seen the problem described in multiple online communities"}),"\n",(0,s.jsx)(t.li,{children:"People have tried to solve it themselves (workarounds, spreadsheets, duct tape solutions)"}),"\n",(0,s.jsx)(t.li,{children:"People have spent money on other solutions to the same problem"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Here's what solution validation looks like:"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"People sign up for a waitlist"}),"\n",(0,s.jsx)(t.li,{children:"People pre-order"}),"\n",(0,s.jsx)(t.li,{children:"People use a prototype and come back"}),"\n"]}),"\n",(0,s.jsx)(t.p,{children:"Problem validation makes solution validation meaningful. Without it, you're guessing."}),"\n",(0,s.jsx)(t.h2,{id:"the-painted-door-test",children:"The Painted Door Test"}),"\n",(0,s.jsx)(t.p,{children:"There's a famous story about a product manager who asked users if they wanted a painted door. Users said yes. Turned out they didn't care about the color. They just wanted to be helpful."}),"\n",(0,s.jsx)(t.p,{children:"Words are cheap. People will tell you they'd use your product because they want to be nice. The only real validation is when people give you something: their time, their money, their email address, their commitment."}),"\n",(0,s.jsx)(t.p,{children:'If you ask someone "would you use this?" and they say yes, ask them to pre-order. Ask them to sign up for a beta. Ask them to introduce you to their team. The yes that costs them something is the only yes that counts.'}),"\n",(0,s.jsx)(t.p,{children:"The Painted Door is everywhere. Users say they want features they never use. They say they'd pay but never open their wallet. They say they'll join the beta but never click the link. This isn't malice. It's human nature. People overestimate their future enthusiasm for anything new."}),"\n",(0,s.jsx)(t.p,{children:"Design your validation tests to account for this. Don't count words. Count actions."}),"\n",(0,s.jsx)(t.h2,{id:"the-hard-truth",children:"The Hard Truth"}),"\n",(0,s.jsx)(t.p,{children:"Your idea is probably not as good as you think it is. Most ideas aren't. The market will tell you this. Listen to it. Don't defend your idea against reality. The faster your idea dies, the faster you can find one that lives."}),"\n",(0,s.jsx)(t.p,{children:"Market research is not a one-time activity. You don't do it before building and then forget about it. You do it continuously. Every conversation with a user is market research. Every support ticket is market research. Every churned customer is market research."}),"\n",(0,s.jsx)(t.p,{children:"Build your feedback loops into your product. Track where users get stuck. Monitor what features they request. Pay attention to the common threads in support emails. Your market is talking to you constantly. Most builders just don't listen."}),"\n",(0,s.jsx)(t.h2,{id:"your-turn",children:"Your Turn"}),"\n",(0,s.jsx)(t.p,{children:"Pick a problem you think exists. Spend 30 minutes on Reddit, Twitter, or a community forum searching for evidence that people actually have this problem."}),"\n",(0,s.jsx)(t.p,{children:"Find three people complaining about it. Write down their exact words. Now ask yourself: is this a real problem or something I imagined?"}),"\n",(0,s.jsx)(t.p,{children:'If you found three genuine complaints, create a "complaints.md" file. Add every complaint you find over the next week. At the end of the week, look for patterns. If one pattern has 5+ complaints from different people, you have a potential market.'}),"\n",(0,s.jsx)(t.p,{children:"Now talk to one person who has this problem. Use the Mom Test. Ask about their life, not your idea. Write down everything you learn."}),"\n",(0,s.jsx)(t.h2,{id:"what-you-learned",children:"What You Learned"}),"\n",(0,s.jsxs)(t.ul,{children:["\n",(0,s.jsx)(t.li,{children:"Market research is just systematic curiosity"}),"\n",(0,s.jsx)(t.li,{children:"Your ability to build gives you a research advantage"}),"\n",(0,s.jsx)(t.li,{children:"The Mom Test helps you ask questions that get honest answers"}),"\n",(0,s.jsx)(t.li,{children:"Reddit, Twitter, and GitHub are free market research tools"}),"\n",(0,s.jsx)(t.li,{children:"Products like Nomad List, Remote OK, and Tally were found through market research"}),"\n",(0,s.jsx)(t.li,{children:"Problem validation must happen before solution validation"}),"\n",(0,s.jsx)(t.li,{children:"Complaints are product opportunities when they form patterns"}),"\n",(0,s.jsx)(t.li,{children:"Analyze competitors to find gaps, not to copy them"}),"\n",(0,s.jsx)(t.li,{children:"Words are cheap \u2014 watch what people do"}),"\n",(0,s.jsx)(t.li,{children:"Validate your idea before you build it"}),"\n"]})]})}function u(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,s.jsx)(t,{...e,children:(0,s.jsx)(d,{...e})}):d(e)}},8453(e,t,o){o.d(t,{R:()=>r,x:()=>a});var n=o(6540);const s={},i=n.createContext(s);function r(e){const t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(s):e.components||s:r(e.components),n.createElement(i.Provider,{value:t},e.children)}}}]);